import{_ as a,o as i,c as n,ai as l}from"./chunks/framework.CsYGeNYI.js";const d=JSON.parse('{"title":"macOS 日志","description":"","frontmatter":{"read_when":["捕获 macOS 日志或调查隐私数据日志记录","调试语音唤醒/会话生命周期问题"],"summary":"OpenSoul 日志：滚动诊断文件日志 + 统一日志隐私标志","title":"macOS 日志","x-i18n":{"generated_at":"2026-02-01T21:32:54Z","model":"claude-opus-4-5","provider":"pi","source_hash":"c4c201d154915e0eb08bf5e32bac98fa93766f50f2a24bf56ab4424eb7781526","source_path":"platforms/mac/logging.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/mac/logging.md","filePath":"zh-CN/platforms/mac/logging.md","lastUpdated":1771906665000}'),e={name:"zh-CN/platforms/mac/logging.md"};function t(p,s,r,o,h,g){return i(),n("div",null,[...s[0]||(s[0]=[l(`<h1 id="日志-macos" tabindex="-1"><a class="header-anchor" href="#日志-macos">#</a> 日志（macOS）</h1><h2 id="滚动诊断文件日志-debug-面板" tabindex="-1"><a class="header-anchor" href="#滚动诊断文件日志-debug-面板">#</a> 滚动诊断文件日志（Debug 面板）</h2><p>OpenSoul 通过 swift-log（默认使用统一日志）路由 macOS 应用日志，并且在需要持久化捕获时可以将本地轮转文件日志写入磁盘。</p><ul><li>详细级别：<strong>Debug 面板 → Logs → App logging → Verbosity</strong></li><li>启用：<strong>Debug 面板 → Logs → App logging → &quot;Write rolling diagnostics log (JSONL)&quot;</strong></li><li>位置：<code>~/Library/Logs/OpenSoul/diagnostics.jsonl</code>（自动轮转；旧文件以 <code>.1</code>、<code>.2</code>、… 为后缀）</li><li>清除：<strong>Debug 面板 → Logs → App logging → &quot;Clear&quot;</strong></li></ul><p>注意事项：</p><ul><li>此功能<strong>默认关闭</strong>。仅在主动调试时启用。</li><li>该文件包含敏感信息；分享前请先审查内容。</li></ul><h2 id="macos-上统一日志的隐私数据" tabindex="-1"><a class="header-anchor" href="#macos-上统一日志的隐私数据">#</a> macOS 上统一日志的隐私数据</h2><p>统一日志会屏蔽大部分负载内容，除非子系统选择启用 <code>privacy -off</code>。根据 Peter 关于 macOS <a href="https://steipete.me/posts/2025/logging-privacy-shenanigans" target="_blank" rel="noreferrer">日志隐私机制</a>（2025）的文章，这通过 <code>/Library/Preferences/Logging/Subsystems/</code> 中以子系统名称为键的 plist 文件来控制。只有新的日志条目才会应用该标志，因此请在复现问题之前启用它。</p><h2 id="为-opensoul-启用-ai-opensoul" tabindex="-1"><a class="header-anchor" href="#为-opensoul-启用-ai-opensoul">#</a> 为 OpenSoul 启用（<code>ai.opensoul</code>）</h2><ul><li>先将 plist 写入临时文件，然后以 root 身份原子性地安装：</li></ul><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;EOF&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/tmp/ai.opensoul.plist</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;?xml version=&quot;1.0&quot; encoding=&quot;UTF-8&quot;?&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;!DOCTYPE plist PUBLIC &quot;-//Apple//DTD PLIST 1.0//EN&quot; &quot;http://www.apple.com/DTDs/PropertyList-1.0.dtd&quot;&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;plist version=&quot;1.0&quot;&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;dict&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &lt;key&gt;DEFAULT-OPTIONS&lt;/key&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &lt;dict&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &lt;key&gt;Enable-Private-Data&lt;/key&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">        &lt;true/&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    &lt;/dict&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;/dict&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&lt;/plist&gt;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">EOF</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 644</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -o</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> root</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -g</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wheel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /tmp/ai.opensoul.plist</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /Library/Preferences/Logging/Subsystems/ai.opensoul.plist</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br><span class="line-number">11</span><br><span class="line-number">12</span><br><span class="line-number">13</span><br><span class="line-number">14</span><br></div></div><ul><li>无需重启；logd 会很快检测到该文件，但只有新的日志行才会包含隐私负载。</li><li>使用现有的辅助脚本查看更丰富的输出，例如 <code>./scripts/opensoul-log.sh --category WebChat --last 5m</code>。</li></ul><h2 id="调试后禁用" tabindex="-1"><a class="header-anchor" href="#调试后禁用">#</a> 调试后禁用</h2><ul><li>移除覆盖配置：<code>sudo rm /Library/Preferences/Logging/Subsystems/ai.opensoul.plist</code>。</li><li>可选择运行 <code>sudo log config --reload</code> 强制 logd 立即丢弃覆盖配置。</li><li>请注意此数据可能包含电话号码和消息正文；仅在确实需要额外详细信息时才保留该 plist 文件。</li></ul>`,14)])])}const k=a(e,[["render",t]]);export{d as __pageData,k as default};
